sql:
SELECT participant_id 
FROM participants 
ORDER BY participant_id;

SELECT session_code
FROM sessions
ORDER BY session_code;

SELECT COUNT(consent_id) 
FROM consents 
WHERE consent_type = 'Research Participation';

